// ❌ GOD FUNCTION (500+ строк)
async function processOrder(orderData) {
  // Валидация
  if (!orderData.email.includes('@')) throw new Error();
  // Проверка инвентаря
  const items = await db.getItems(orderData.items);
  if (items.some(i => i.stock < i.qty)) throw new Error();
  // Расчет цены
  let total = 0;
  for (let item of items) {
    total += item.price * item.qty;
  }
  if (orderData.coupon) {
    total = applyCoupon(total, orderData.coupon);
  }
  // Создание платежа
  const payment = await stripe.createPayment(total);
  // Отправка email
  await sendEmail(orderData.email, 'Order confirmed');
  // Запись в БД
  await db.orders.insert({ ...orderData, total, paymentId: payment.id });
  // Обновление инвентаря
  for (let item of items) {
    await db.updateStock(item.id, item.stock - item.qty);
  }
  // Логирование
  logger.info('Order created', orderData);
  return payment;
}

// ✅ Разделение ответственности
class OrderService {
  constructor(orderValidator, inventoryService, paymentService, emailService) {
    this.validator = orderValidator;
    this.inventory = inventoryService;
    this.payment = paymentService;
    this.email = emailService;
  }

  async createOrder(orderData) {
    this.validator.validate(orderData);
    const items = await this.inventory.reserve(orderData.items);
    const total = this.calculateTotal(items, orderData.coupon);
    const payment = await this.payment.charge(total);
    await this.email.sendConfirmation(orderData.email);
    return this.saveOrder(orderData, items, total, payment);
  }
}

