// ❌ RACE CONDITION (check-then-act)
async function withdraw(accountId, amount) {
  const balance = await db.getBalance(accountId); // 100

  if (balance >= amount) { // true
    // <-- Другой запрос уже снял деньги! Баланс теперь 50
    await db.setBalance(accountId, balance - amount);
    // Результат: -50 (перерасход!)
  }
}

// ✅ АТОМАРНАЯ ОПЕРАЦИЯ
async function withdraw(accountId, amount) {
  // SQL: UPDATE accounts SET balance = balance - ? WHERE id = ? AND balance >= ?
  const result = await db.query(
    'UPDATE accounts SET balance = balance - $1 WHERE id = $2 AND balance >= $1',
    [amount, accountId]
  );

  if (result.rowCount === 0) {
    throw new Error('Insufficient funds');
  }
}

// ❌ RACE в React
function Counter() {
  const [count, setCount] = useState(0);

  const increment = () => {
    // Множественные быстрые клики = race condition!
    setCount(count + 1); // count может быть устаревшим
  };

  // ✅ Используем функциональное обновление
  const increment = () => {
    setCount(prev => prev + 1); // всегда актуальное значение
  };
}

